


CREATE     proc--  exec
[dbo].[marketing_attribution_creation]-- 1
 @num int = 13
as

begin
   declare @date___ date = getdate()-@num
   	if @num = -1 
	set @date___  = '20221107'
   --declare @date___ date = '20221107'



DROP TABLE IF EXISTS #TMP_leads
CREATE TABLE #TMP_leads
(
	[ID] [numeric](10, 0) NOT NULL,
	[PhoneNumber] [varchar](20) NULL,
	[UF_REGISTERED_AT] [datetime2](7) NULL,
	[UF_STAT_AD_TYPE] [varchar](512) NULL,
	[UF_STAT_CAMPAIGN] [varchar](512) NULL,
	[UF_SOURCE] [varchar](512) NULL,
	UF_TYPE [varchar](512) NULL
	

)

-- 
DECLARE @Return_Table_Name varchar(100)
DECLARE @Return_Number int, @Return_Message varchar(1000)
DECLARE	@Begin_Registered date, @End_Registered date

--название таблицы, которая будет заполнена
SELECT @Return_Table_Name = '#TMP_leads'
SELECT @Begin_Registered = @date___ , @End_Registered = getdate()


--EXEC Stg._LCRM.get_leads
--	@Debug = 0, -- 0 - штатное выполнение, 1 - отладочный режим
--	@Begin_Registered = @Begin_Registered, -- начальная дата
--	@End_Registered = @End_Registered, -- конечная дата
--	@Return_Table_Name = @Return_Table_Name, -- название таблицы для возвращения записей
--	@Return_Number = @Return_Number OUTPUT, -- возвращаемый код, 0 - без ошибок
--	@Return_Message = @Return_Message OUTPUT -- возвращаемое сообщение

SELECT @Return_Number, @Return_Message

--select * from #f
--order by 4

  -- declare @date___ date = getdate()-1
drop table if exists  [#f]
  CREATE TABLE  .[#f]
(
      [phonenumber] [VARCHAR](20)
    , [Канал от источника] [VARCHAR](50)
    , [type] [VARCHAR](4)
    , [dt] [DATETIME2](7)
    , [id] [numeric](18,0)
    , [lead_id] nvarchar(50)
    ,source nvarchar(128)
);

  insert   into #f 
select phonenumber, [Канал от источника], type, dt, id , null, null  from (
select phonenumber,
case

when uf_type   in ( 'site3_gazprom_bank', 'site3_gazprom_bank_installment')  then 'Газпром'
when uf_type   in ( 'site3_soyuz_installment', 'site3_soyuz')      then 'Союз'
when uf_source in ( 'bank-souz-ref', 'bank-souz-installment-ref')  then 'Союз'
when uf_type = 'site3_installment_lk' and uf_stat_campaign = '5387'  then 'Союз'
when [UF_STAT_AD_TYPE] = 'partner' and uf_stat_campaign = '5387'  then 'Союз'
when [UF_STAT_AD_TYPE] = 'partner' and uf_stat_campaign = '150'  then 'Союз'
when uf_source in ( 'beeline', 'beeline-installment', 'beeline-telekom')  then 'Билайн'
when uf_source in ( 'tochkabank-installment-ref', 'tochkabank-ref')  then 'Точка'
when uf_type = 'site3_installment_lk' and uf_stat_campaign = '5469'  then 'Модуль'
end	 [Канал от источника]  ,
type = 'lead',
dt = uf_registered_at ,
id = id	,
cast(id as nvarchar(36)) lead_id
from #TMP_leads 
--from dm_lcrm_leads_for_report
) x
where x.[Канал от источника] is not null
--and 1=0



  insert   into #f 
select phonenumber, [Канал от источника], type, dt, id , lead_id, source   from (
select a.phone phonenumber,
case
when source_account.name  IN ( 'tpokupki-big-installment')  then 'Т-Банк'
when source_account.name  IN ( 'psb-msb')  then 'ПСБ'
when source_account.name  IN ( 'tpokupki-deepapi')  then 'Т-Банк'
when source_account.name  IN ( 'infoseti')  then 'CPA целевой'
when source_account.name  IN ( 'psb-deepapi')  then 'ПСБ'
when source_account.name  IN ( 'levoberezhniy-ref')  then 'Левобережный'
when source_account.name  IN ( 'infoseti-deepapi-pts')  then 'CPA целевой'
when source_account.name  IN ('infoseti-deepapi-installment' )  then 'CPA полуцелевой'
when type_code   in ( 'site3_gazprom_bank', 'site3_gazprom_bank_installment')  then 'Газпром'
when type_code   in ( 'site3_soyuz_installment', 'site3_soyuz')      then 'Союз'
when source_account.name in ( 'bank-souz-ref', 'bank-souz-installment-ref')  then 'Союз'
when type_code = 'site3_installment_lk' and v.stat_campaign = '5387'  then 'Союз'
when v.stat_type = 'partner' and v.stat_campaign = '5387'  then 'Союз'
when v.stat_type = 'partner' and v.stat_campaign = '150'  then 'Союз'
when source_account.name in ( 'beeline', 'beeline-installment', 'beeline-telekom')  then 'Билайн'
when source_account.name in ( 'tochkabank-installment-ref', 'tochkabank-ref')  then 'Точка'
when type_code = 'site3_installment_lk' and v.stat_campaign = '5469'  then 'Модуль'
when source_account.name in ( 'psb-installment-ref', 'psb-ref')  then 'ПСБ'
when source_account.name in ( 'vtb-installment-ref', 'vtb-ref') and   entrypoint_id='5d43a3aa-bedc-4455-a37e-a691d066bcf4' and cast(a.created_at_time as date) not in ('20240821' , '20240822' , '20240820')  then 'ВТБ'
when source_account.name in ( 'vtb-installment-ref', 'vtb-ref') and   entrypoint_id<>'5d43a3aa-bedc-4455-a37e-a691d066bcf4'  then 'ВТБ'
end	 [Канал от источника]  ,
type = 'lf',
dt = a.created_at_time ,
id = null	,
a.id lead_id
, case
when source_account.name  IN ( 'tpokupki-big-installment')  then  source_account.name

when source_account.name  IN ( 'psb-msb')  then  source_account.name
when source_account.name  IN ( 'tpokupki-deepapi')  then  source_account.name
when source_account.name  IN ( 'infoseti')  then  source_account.name
when source_account.name  IN ( 'psb-deepapi')    then  source_account.name
when source_account.name  IN ( 'infoseti-deepapi-pts')  then  source_account.name
when source_account.name  IN ('infoseti-deepapi-installment' )  then  source_account.name end source


from stg._lf.lead  a
left join stg._lf.referral_visit v on v.id=a.visit_id
left join stg._lf.source_account on source_account.id=a.source_id
--from dm_lcrm_leads_for_report
) x
where x.[Канал от источника] is not null	 and dt between 	   @date___ and    getdate()



--and 1=0



drop table if exists #Документ_ЗаявкаНаЗаймПодПТС
select      dateadd(year, -2000,  Дата ) Дата
,      МобильныйТелефон
,     ссылка
into #Документ_ЗаявкаНаЗаймПодПТС
from stg._1cCRM.Документ_ЗаявкаНаЗаймПодПТС
where cast( dateadd(year, -2000,  Дата ) as date) between @date___ and getdate()

drop table if exists #Справочник_офисы
select Ссылка, Родитель, Наименование, Код , Партнер into #Справочник_офисы from stg._1cCRM.Справочник_Офисы

drop table if exists [#РегистрСведений_ИзмененияВидаЗаполненияВЗаявках]
select Заявка, Офис, ДатаИзменения into  [#РегистрСведений_ИзмененияВидаЗаполненияВЗаявках]
FROM [Stg].[_1cCRM].[РегистрСведений_ИзмененияВидаЗаполненияВЗаявках]

--drop table if exists [#Справочник_Партнеры]
--select Ссылка, Наименование into [#Справочник_Партнеры] 
--from [Stg].[_1cCRM].[Справочник_Партнеры] a
--join (select distinct Партнер from #Справочник_офисы ) b on a.Ссылка=b.Партнер

--drop table if exists [#Движение заявки по точка]
;

	  with v as(
select c.Ссылка,  Дата, МобильныйТелефон,  o.Код [Номер точки при создании], ROW_NUMBER() over(partition by c.Ссылка order by ДатаИзменения) rn 
from
#Документ_ЗаявкаНаЗаймПодПТС c join
[#РегистрСведений_ИзмененияВидаЗаполненияВЗаявках] a on a.Заявка=c.Ссылка
left join #Справочник_офисы o on a.Офис=o.Ссылка
--left join [#Справочник_Партнеры] ozz_p on o.Партнер=ozz_p.Ссылка

)
insert into #f
select v.МобильныйТелефон, 'Союз' [Канал от источника] ,type = 'lkp' , Дата dt	, null , null, null
from v
where rn=1 and [Номер точки при создании]='5387'

insert into #f
select мобильный, 'МТС', type = '', dt = База , null, null, null from [Трафик МТС таблица]
where 	 cast( База as date)  between @date___ and getdate()






insert into #f
select мобильный, 'Союз', type = '', dt = База, null, null, null from [Трафик союз таблица]
where 	 cast( База as date)    between @date___ and getdate()

